import { createApp } from 'vue';
import { createRouter, createWebHashHistory } from 'vue-router';
import App from './App.vue';
import './assets/css/scroll-animations.css';
import AboutTab from './components/AboutTab.vue';
import EducationTab from './components/EducationTab.vue';
import ExperienceTab from './components/ExperienceTab.vue';
import ResearchTab from './components/ResearchTab.vue';
import ProjectsTab from './components/ProjectsTab.vue';
import JourneyTab from './components/JourneyTab.vue';
import PlaybookTab from './components/PlaybookTab.vue';
import LexadayPage from './components/LexadayPage.vue';
import DealtrackerPage from './components/DealtrackerPage.vue';
import ScrollytellingPage from './components/ScrollytellingPage.vue';
import EarlyPage from './components/EarlyPage.vue';
import FragmentsTab from './components/FragmentsTab.vue';
import TrafficTab from './components/TrafficTab.vue';
import ResumeTab from './components/ResumeTab.vue';
import IndexPage from './components/IndexPage.vue';
import VueGtag from "vue-gtag-next";

// Define your routes with meta titles
const routes = [
  { path: '/about', component: AboutTab, meta: { title: 'About - H.W.' } },
  { path: '/education', component: EducationTab, meta: { title: 'Education - H.W.' } },
  { path: '/experience', component: ExperienceTab, meta: { title: 'Experience - H.W.' } },
  { path: '/research', component: ResearchTab, meta: { title: 'Research - H.W.' } },
  { path: '/projects', component: ProjectsTab, meta: { title: 'Projects - H.W.' } },
  { path: '/travels', component: JourneyTab, meta: { title: 'Travels - H.W.' } },
  { path: '/playbook', component: PlaybookTab, meta: { title: 'Omni Playbook - H.W.' } },
  { path: '/lexaday', component: LexadayPage, meta: { title: 'Lexaday - H.W.' } },
  { path: '/dealtracker', component: DealtrackerPage, meta: { title: 'Dealtracker - H.W.' } },
  { path: '/scrollytelling', component: ScrollytellingPage, meta: { title: 'Scrollytelling Engine - H.W.' } },
  { path: '/early', component: EarlyPage, meta: { title: 'Early CS Adventure - H.W.' } },
  { path: '/fragments', component: FragmentsTab, meta: { title: 'Fragments - H.W.' } },
  { path: '/traffic', component: TrafficTab, meta: { title: 'Traffic - H.W.' } },
  { path: '/cv', component: ResumeTab, meta: { title: 'CV - Han-yu Wang' } },
  { path: '/home', component: IndexPage, meta: { title: 'Home - H.W.' } },
  { path: '/', component: IndexPage, meta: { title: 'H.W. | An enthusiastic explorer' } }
];

// Create the router instance
const router = createRouter({
  history: createWebHashHistory(),
  routes,
  scrollBehavior(to, from, savedPosition) {
    // If user clicks browser back/forward, restore scroll
    if (savedPosition) {
      return savedPosition;
    }
    // Returning to a specific section (e.g. /projects?to=dealtracker): let the
    // target page position itself, don't reset to the top first.
    if (to.query && to.query.to) {
      return false;
    }
    // A query-only change on the same page (e.g. stripping the ?to intent after
    // it's been consumed): leave the scroll position alone.
    if (from.path === to.path) {
      return false;
    }
    // Otherwise scroll to top for new routes
    return { top: 0 };
  }
});

// Create the Vue app instance
const app = createApp(App);

// Use the Google Analytics plugin with your Tracking ID
app.use(VueGtag, {
  property: {
    id: "G-WED90XV0C9"  // Your Google Analytics Tracking ID
  }
}, router);

// After each route change, update the document title and trigger a Google Analytics page view
router.afterEach((to) => {
  const pageTitle = to.meta.title || 'H.W. | An enthusiastic explorer';
  const pagePath = to.fullPath;

  document.title = pageTitle;
  
  // // Log the title and path being sent to Google Analytics
  // console.log('Sending to Google Analytics:');
  // console.log('Page Title:', pageTitle);
  // console.log('Page Path:', pagePath);
  
  // Trigger Google Analytics page view using vue-gtag-next
  app.config.globalProperties.$gtag.pageview({
    page_path: pagePath,
    page_title: pageTitle,
  });
});

// Use the router
app.use(router);

// Mount the app
app.mount('#app');
